 1	import { useObjectMetadataItem } from '@/object-metadata/hooks/useObjectMetadataItem';
 2	import { formatFieldMetadataItemAsColumnDefinition } from '@/object-metadata/utils/formatFieldMetadataItemAsColumnDefinition';
 3	import { useUpdateOneRecord } from '@/object-record/hooks/useUpdateOneRecord';
 4	import { useIsRecordFieldReadOnly } from '@/object-record/read-only/hooks/useIsRecordFieldReadOnly';
 5	import {
 6	  FieldContext,
 7	  type RecordUpdateHook,
 8	  type RecordUpdateHookParams,
 9	} from '@/object-record/record-field/ui/contexts/FieldContext';
10	import { type ReactNode } from 'react';
11	
12	export const FieldContextProvider = ({
13	  clearable,
14	  fieldMetadataName,
15	  fieldPosition,
16	  isLabelIdentifier = false,
17	  objectNameSingular,
18	  objectRecordId,
19	  customUseUpdateOneObjectHook,
20	  overridenIsFieldEmpty,
21	  onMouseEnter,
22	  anchorId,
23	  children,
24	}: {
25	  clearable?: boolean;
26	  fieldMetadataName: string;
27	  fieldPosition: number;
28	  isLabelIdentifier?: boolean;
29	  objectNameSingular: string;
30	  objectRecordId: string;
31	  customUseUpdateOneObjectHook?: RecordUpdateHook;
32	  overridenIsFieldEmpty?: boolean;
33	  onMouseEnter?: () => void;
34	  anchorId?: string;
35	  children: ReactNode;
36	}) => {
37	  const { objectMetadataItem } = useObjectMetadataItem({
38	    objectNameSingular,
39	  });
40	
41	  const fieldMetadataItem = objectMetadataItem?.fields.find(
42	    (field) => field.name === fieldMetadataName,
43	  );
44	
45	  const { updateOneRecord } = useUpdateOneRecord();
